sql:
SELECT number_of_professionals_added, total_number_of_pros, growth_rate
FROM yearly_stats
WHERE year = 0;

external_knowledge:
- 'Medical Professionals' refers to professionals in the category with the name 'Medical Professionals';
- 'Active professionals' refers to professionals with a status of 'active';
- 'Growth rate' is calculated by comparing the number of active professionals in the current year to the number in the previous year.

sql:
SELECT total_number_of_pros
FROM yearly_stats
WHERE year = (SELECT MAX(year) FROM yearly_stats);

SELECT number_of_professionals_added AS total_added
FROM yearly_stats
WHERE year = 2021;

SELECT year
FROM yearly_stats
WHERE number_of_professionals_added = (SELECT MAX(number_of_professionals_added) FROM yearly_stats);

